import{_ as t,c as e,o as a,aR as i}from"./chunks/framework.loP4pEEE.js";const m=JSON.parse('{"title":"曾楚龙","titleTemplate":"个人简历","description":"","frontmatter":{"titleTemplate":"个人简历"},"headers":[],"relativePath":"intro/index.md","filePath":"intro/index.md","lastUpdated":null}'),r={name:"intro/index.md"},l=i('<h1 id="曾楚龙" tabindex="-1">曾楚龙 <a class="header-anchor" href="#曾楚龙" aria-label="Permalink to &quot;曾楚龙&quot;">​</a></h1><p>博客 💻 <a href="https://blog.hisher.site" target="_blank" rel="noreferrer">https://blog.hisher.site</a></p><p>邮箱 📧 <a href="mailto:shawn1440982358@163.com" target="_blank" rel="noreferrer">shawn1440982358@163.com</a></p><p>电话&amp;微信 📞 <a href="tel:+8618680271761" target="_blank" rel="noreferrer">18680271761</a></p><h2 id="自我介绍" tabindex="-1">自我介绍 <a class="header-anchor" href="#自我介绍" aria-label="Permalink to &quot;自我介绍&quot;">​</a></h2><ul><li>💪 2019年开始独立对接项目，<strong>4年</strong> 前端开发经验，<strong>2年</strong> 后端开发经验，<strong>半年</strong>全栈开发经验。</li><li>👨🏻‍💻 具备需求对接、文档编写、技术选型、服务器选购、域名购买、部署和上线的能力。</li><li>🏆 大学期间获得省、国家级各类创赛奖项若干（包含第八届大学生软件杯全国一等奖）。</li></ul><h2 id="开发能力" tabindex="-1">开发能力 <a class="header-anchor" href="#开发能力" aria-label="Permalink to &quot;开发能力&quot;">​</a></h2><h3 id="前端开发" tabindex="-1">前端开发 <a class="header-anchor" href="#前端开发" aria-label="Permalink to &quot;前端开发&quot;">​</a></h3><ul><li><strong>核心技术：</strong> 精通使用Vue3全家桶、Uniapp跨端框架、小程序原生语法、ES6语法、TypeScript语言。</li><li><strong>审美优化：</strong> 精通使用Bootstrap响应式的TailwindCSS、UnoCSS、ElementPlus、uView等优秀组件库。</li><li><strong>页面还原：</strong> <strong>100%</strong> 还原设计图、设计稿和交互。</li><li><strong>项目经验：</strong> 独立或团队开发了多个PC端、移动端应用、H5官网、后台管理系统以及微信（支付宝，抖音）小程序。具备独立站建设经验。</li><li><strong>渲染技术：</strong> 擅长SEO搜索引擎优化，熟悉服务端渲染和预渲染技术。</li></ul><h3 id="后端开发" tabindex="-1">后端开发 <a class="header-anchor" href="#后端开发" aria-label="Permalink to &quot;后端开发&quot;">​</a></h3><ul><li><strong>编程语言：</strong> 熟练掌握Java编程语言，精通SpringBoot框架，运用MyBatisPlus进行高效数据操作。</li><li><strong>分布式开发：</strong> 具备分布式系统开发经验，熟悉相关技术如Redis、RocketMQ等。</li></ul><h2 id="个人能力" tabindex="-1">个人能力 <a class="header-anchor" href="#个人能力" aria-label="Permalink to &quot;个人能力&quot;">​</a></h2><ul><li>具备需求对接、文档编写、技术选型、服务器选型、部署、上线、调优、交付和维护工作。</li><li>服务器选配、购买、配置、优化、ssl证书认证、域名解析</li><li>本地git仓库搭建、ssh密钥配置、git分支管理、git提交命名规范</li><li>项目技术选型、框架搭建、Readme.md、技术文档和操作文档编写</li><li>项目打包、压缩、SSG静态运行、pm2守护进程运行、SEO搜索引擎优化、nginx反向代理</li><li>项目维护、性能调优、日志记录</li></ul><h2 id="项目介绍" tabindex="-1">项目介绍 <a class="header-anchor" href="#项目介绍" aria-label="Permalink to &quot;项目介绍&quot;">​</a></h2><h3 id="领辰移民官网-pc官网" tabindex="-1">领辰移民官网：PC官网 <a class="header-anchor" href="#领辰移民官网-pc官网" aria-label="Permalink to &quot;领辰移民官网：PC官网&quot;">​</a></h3><ul><li><em>一款提供移民服务的网页端web平台，具有社区聊天、文章、项目、用户、支付等功能</em></li><li><em>按照 Figma 设计稿，实现页面还原，并使用 ElementPlus 等优秀组件库，实现页面交互。</em></li><li><em>优秀的 SEO 搜索引擎优化，提高了百度和谷歌的收录页面数量，使用预渲染技术生成静态页面，同时配置服务端压缩，使首次访问页面的加载体积减少 <strong>50%</strong> ，加载耗时减少 <strong>30%</strong>，针对客服和地图等组件，实现客户端按需加载，极大丰富了网站的使用场景。</em></li></ul><div class="tip custom-block"><p class="custom-block-title">技术栈</p><ul><li>🔥 Nuxt3、SEO、SSR - 通过利用服务器端渲染，ESM格式和优化的图像，网站可由搜索引擎索引，同时为最终用户提供应用程序的感觉</li><li>📥 数据获取、状态管理、元标记帮助程序、路由防护、cookie、错误处理、捆绑分析器。</li><li>🌈 Vue3、Vite4、ES6、pnpm - 现阶段最优秀的前端开发框架</li><li>🎨 Layout、Flex、Grid、ElementPlus、Animation、TailwindCSS - 按需调用优秀的组件库、敏捷开发页面、实现快速迭代</li><li>📦 PM2进程守护、Nginx反向代理、gzip压缩开启 - 服务端配置优化</li></ul></div><h4 id="官网首页" tabindex="-1"><a href="https://lc.plus" target="_blank" rel="noreferrer">官网首页</a><img src="https://www.hisher.site/pic/intro/LC_PC_HOME.png" alt=""> <a class="header-anchor" href="#官网首页" aria-label="Permalink to &quot;[官网首页](https://lc.plus)![](https://www.hisher.site/pic/intro/LC_PC_HOME.png)&quot;">​</a></h4><h4 id="项目列表" tabindex="-1"><a href="https://lc.plus/project" target="_blank" rel="noreferrer">项目列表</a><img src="https://www.hisher.site/pic/intro/LC_PC_PROJECT.png" alt=""> <a class="header-anchor" href="#项目列表" aria-label="Permalink to &quot;[项目列表](https://lc.plus/project)![](https://www.hisher.site/pic/intro/LC_PC_PROJECT.png)&quot;">​</a></h4><h4 id="文章列表" tabindex="-1"><a href="https://lc.plus/article" target="_blank" rel="noreferrer">文章列表</a><img src="https://www.hisher.site/pic/intro/LC_PC_ARTICLE.png" alt=""> <a class="header-anchor" href="#文章列表" aria-label="Permalink to &quot;[文章列表](https://lc.plus/article)![](https://www.hisher.site/pic/intro/LC_PC_ARTICLE.png)&quot;">​</a></h4><h4 id="关于我们" tabindex="-1"><a href="https://lc.plus/about" target="_blank" rel="noreferrer">关于我们</a><img src="https://www.hisher.site/pic/intro/LC_PC_ABOUT.png" alt=""> <a class="header-anchor" href="#关于我们" aria-label="Permalink to &quot;[关于我们](https://lc.plus/about)![](https://www.hisher.site/pic/intro/LC_PC_ABOUT.png)&quot;">​</a></h4><h3 id="领辰移民小程序-手机端平台" tabindex="-1">领辰移民小程序：手机端平台 <a class="header-anchor" href="#领辰移民小程序-手机端平台" aria-label="Permalink to &quot;领辰移民小程序：手机端平台&quot;">​</a></h3><ul><li><em>一款提供移民服务的手机端平台，具有社区聊天、文章、项目、用户、支付等功能</em></li><li><em>按照 Figma 设计稿，实现页面还原，并使用 uView 等优秀组件库，实现页面交互。</em></li><li><em>基于 uniapp 开发，可快速部署在网页端、小程序、App，微信、支付宝、抖音等平台。</em></li></ul><div class="tip custom-block"><p class="custom-block-title">技术栈</p><ul><li>⚡️ Vue 3、Vite、pnpm、esbuild、TypeScript - 就是快！</li><li>🎨 UnoCSS - 高性能且极具灵活性的即时原子化 CSS 引擎</li><li>🦾 Pritter &amp; ESLint &amp; Stylelint &amp; husky &amp; lint-staged + commitlint - 保证代码质量</li><li>🍍 pinia &amp; pinia-plugin-persistedstate - 全端适配的全局数据管理</li></ul></div><h4 id="程序首页" tabindex="-1"><a href="https://m.lc.plus" target="_blank" rel="noreferrer">程序首页</a><img src="https://www.hisher.site/pic/intro/LC_M_HOME.png" alt=""> <a class="header-anchor" href="#程序首页" aria-label="Permalink to &quot;[程序首页](https://m.lc.plus)![](https://www.hisher.site/pic/intro/LC_M_HOME.png)&quot;">​</a></h4><h4 id="项目列表-1" tabindex="-1"><a href="https://m.lc.plus/project" target="_blank" rel="noreferrer">项目列表</a><img src="https://www.hisher.site/pic/intro/LC_M_PROJECT.png" alt=""> <a class="header-anchor" href="#项目列表-1" aria-label="Permalink to &quot;[项目列表](https://m.lc.plus/project)![](https://www.hisher.site/pic/intro/LC_M_PROJECT.png)&quot;">​</a></h4><h4 id="文章列表-1" tabindex="-1"><a href="https://m.lc.plus/article" target="_blank" rel="noreferrer">文章列表</a><img src="https://www.hisher.site/pic/intro/LC_M_ARTICLE_LIST.png" alt=""> <a class="header-anchor" href="#文章列表-1" aria-label="Permalink to &quot;[文章列表](https://m.lc.plus/article)![](https://www.hisher.site/pic/intro/LC_M_ARTICLE_LIST.png)&quot;">​</a></h4><h4 id="用户界面" tabindex="-1"><a href="https://m.lc.plus/user" target="_blank" rel="noreferrer">用户界面</a><img src="https://www.hisher.site/pic/intro/LC_M_USER.png" alt=""> <a class="header-anchor" href="#用户界面" aria-label="Permalink to &quot;[用户界面](https://m.lc.plus/user)![](https://www.hisher.site/pic/intro/LC_M_USER.png)&quot;">​</a></h4><h3 id="象小美租手机-支付宝小程序" tabindex="-1">象小美租手机：支付宝小程序 <a class="header-anchor" href="#象小美租手机-支付宝小程序" aria-label="Permalink to &quot;象小美租手机：支付宝小程序&quot;">​</a></h3><ul><li><em>一款可以在支付宝上面自由租赁的小程序，基于支付宝原生语言开发，无缝对接官方sdk</em></li></ul><h4 id="首页" tabindex="-1">首页<img src="https://www.hisher.site/pic/intro/XZ_M_HOME.webp" alt=""> <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页![](https://www.hisher.site/pic/intro/XZ_M_HOME.webp)&quot;">​</a></h4><h4 id="分类" tabindex="-1">分类<img src="https://www.hisher.site/pic/intro/XZ_M_CATEGORY.webp" alt=""> <a class="header-anchor" href="#分类" aria-label="Permalink to &quot;分类![](https://www.hisher.site/pic/intro/XZ_M_CATEGORY.webp)&quot;">​</a></h4><h4 id="商品" tabindex="-1">商品<img src="https://www.hisher.site/pic/intro/XZ_M_PRODUCT.webp" alt=""> <a class="header-anchor" href="#商品" aria-label="Permalink to &quot;商品![](https://www.hisher.site/pic/intro/XZ_M_PRODUCT.webp)&quot;">​</a></h4><h4 id="订单确认" tabindex="-1">订单确认<img src="https://www.hisher.site/pic/intro/XZ_M_ORDER_CONFIRM.webp" alt=""> <a class="header-anchor" href="#订单确认" aria-label="Permalink to &quot;订单确认![](https://www.hisher.site/pic/intro/XZ_M_ORDER_CONFIRM.webp)&quot;">​</a></h4><h4 id="用户界面-1" tabindex="-1">用户界面<img src="https://www.hisher.site/pic/intro/XZ_M_USER.webp" alt=""> <a class="header-anchor" href="#用户界面-1" aria-label="Permalink to &quot;用户界面![](https://www.hisher.site/pic/intro/XZ_M_USER.webp)&quot;">​</a></h4><h3 id="氪金达人商城-h5移动端应用" tabindex="-1">氪金达人商城：H5移动端应用 <a class="header-anchor" href="#氪金达人商城-h5移动端应用" aria-label="Permalink to &quot;氪金达人商城：H5移动端应用&quot;">​</a></h3><ul><li><em>港澳台玩家专属的H5游戏点卡充值商城</em></li></ul><h4 id="首页-1" tabindex="-1"><a href="https://game-853.com/" target="_blank" rel="noreferrer">首页</a><img src="https://www.hisher.site/pic/intro/GAME_M_HOME.webp" alt=""> <a class="header-anchor" href="#首页-1" aria-label="Permalink to &quot;[首页](https://game-853.com/)![](https://www.hisher.site/pic/intro/GAME_M_HOME.webp)&quot;">​</a></h4><h4 id="点卡" tabindex="-1"><a href="https://game-853.com/" target="_blank" rel="noreferrer">点卡</a><img src="https://www.hisher.site/pic/intro/GAME_M_POINT.webp" alt=""> <a class="header-anchor" href="#点卡" aria-label="Permalink to &quot;[点卡](https://game-853.com/)![](https://www.hisher.site/pic/intro/GAME_M_POINT.webp)&quot;">​</a></h4><h3 id="中后台管理系统-自适应手机和电脑布局" tabindex="-1">中后台管理系统：自适应手机和电脑布局 <a class="header-anchor" href="#中后台管理系统-自适应手机和电脑布局" aria-label="Permalink to &quot;中后台管理系统：自适应手机和电脑布局&quot;">​</a></h3><ul><li><em>拥有完整的文章管理、用户管理、项目管理、评论管理、权限管理、角色管理、菜单管理、日志管理、系统设置等功能。</em></li><li><em>支持增删改查、分页、搜索、导出、导入</em></li></ul><div class="tip custom-block"><p class="custom-block-title">技术栈</p><ul><li>⚡️ 完全采用 ECMAScript 模块（ESM）规范来编写和组织代码，</li><li>🔑 采用目前最常用的 RBAC 基于角色的权限控制（ 用户 -&gt; 角色 -&gt; 权限 ），可配置各种粒度的权限</li><li>🔩 高度可配置的主题以及暗黑主题适配，并且提供左侧、顶部、综合这三种菜单布局模式</li><li>🔥 基于Vue3、Vite、Element-Plus、TypeScript、Pinia、Tailwindcss等最新技术栈开发</li><li>🍭 Wangeditor富文本编辑器、dayjs、echarts - 丰富的第三方库</li></ul></div><h4 id="系统功能" tabindex="-1">系统功能 <a class="header-anchor" href="#系统功能" aria-label="Permalink to &quot;系统功能&quot;">​</a></h4><table><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td>用户管理</td><td>用户是系统操作者，该功能主要完成系统用户配置</td></tr><tr><td>部门管理</td><td>配置系统组织机构（公司、部门、小组），树结构展现支持数据权限</td></tr><tr><td>岗位管理</td><td>配置系统用户所属担任职务</td></tr><tr><td>菜单管理</td><td>配置系统菜单、操作权限、按钮权限标识等，本地缓存提供性能</td></tr><tr><td>角色管理</td><td>角色菜单权限分配、设置角色按机构进行数据范围权划分</td></tr><tr><td>参数管理</td><td>对系统动态配置常用参数</td></tr><tr><td>通知公告</td><td>系统通知公告信息发布维护</td></tr><tr><td>操作日志</td><td>系统正常操作日志记录和查询；系统异常信息日志记录和查询</td></tr><tr><td>登录日志</td><td>系统登录日志记录查询包含登录异常</td></tr><tr><td>在线用户</td><td>当前系统中活跃用户状态监控</td></tr><tr><td>系统接口</td><td>根据业务代码自动生成相关的 api 接口文档</td></tr><tr><td>服务监控</td><td>监视当前系统 CPU、内存、磁盘、堆栈等相关信息</td></tr><tr><td>缓存监控</td><td>对系统的缓存信息查询，命令统计等</td></tr><tr><td>连接池监视</td><td>监视当前系统数据库连接池状态，可进行分析 SQL 找出系统性能瓶颈</td></tr></tbody></table><h4 id="用户界面-2" tabindex="-1">用户界面<img src="https://www.hisher.site/pic/intro/GAME_ADMIN_USER.webp" alt=""> <a class="header-anchor" href="#用户界面-2" aria-label="Permalink to &quot;用户界面![](https://www.hisher.site/pic/intro/GAME_ADMIN_USER.webp)&quot;">​</a></h4><h4 id="角色界面" tabindex="-1">角色界面<img src="https://www.hisher.site/pic/intro/GAME_ADMIN_ROLE.webp" alt=""> <a class="header-anchor" href="#角色界面" aria-label="Permalink to &quot;角色界面![](https://www.hisher.site/pic/intro/GAME_ADMIN_ROLE.webp)&quot;">​</a></h4><h4 id="文章列表-2" tabindex="-1">文章列表<img src="https://www.hisher.site/pic/intro/LC_ADMIN_ARTICLE_LIST.webp" alt=""> <a class="header-anchor" href="#文章列表-2" aria-label="Permalink to &quot;文章列表![](https://www.hisher.site/pic/intro/LC_ADMIN_ARTICLE_LIST.webp)&quot;">​</a></h4><h4 id="发布文章" tabindex="-1">发布文章<img src="https://www.hisher.site/pic/intro/LC_ADMIN_POST_ARTICLE.webp" alt=""> <a class="header-anchor" href="#发布文章" aria-label="Permalink to &quot;发布文章![](https://www.hisher.site/pic/intro/LC_ADMIN_POST_ARTICLE.webp)&quot;">​</a></h4><h2 id="多语言能力" tabindex="-1">多语言能力 <a class="header-anchor" href="#多语言能力" aria-label="Permalink to &quot;多语言能力&quot;">​</a></h2><ul><li>中文、繁体中文、粤语、英语流畅交流和对接</li></ul><h2 id="英语能力" tabindex="-1">英语能力 <a class="header-anchor" href="#英语能力" aria-label="Permalink to &quot;英语能力&quot;">​</a></h2><ul><li>英语阅读、口语、交流、对接</li><li>全英文官方源码、规范命名</li></ul><h2 id="能力拓展" tabindex="-1">能力拓展 <a class="header-anchor" href="#能力拓展" aria-label="Permalink to &quot;能力拓展&quot;">​</a></h2><ul><li>便于个人积累，我开发基于vitepress的<a href="https://blog.hisher.site" target="_blank" rel="noreferrer">个人博客</a>，将其部署在我的个人服务器上</li><li>通过网站托管平台生成我的<a href="https://clung-tsang-github-io.vercel.app/" target="_blank" rel="noreferrer">Vercel站点</a>和<a href="https://clungtsang.github.io/" target="_blank" rel="noreferrer">Github站点</a></li><li>持续关注AIGC技术</li></ul>',54),h=[l];function s(o,n,p,c,d,u){return a(),e("div",null,h)}const b=t(r,[["render",s]]);export{m as __pageData,b as default};
